import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Use nextLine() instead of next() to read the whole line

        // Define buffer size
        int bufferSize = 10;

        // Copying the user input into the buffer array with proper bounds checking
        char[] buffer = new char[bufferSize];

        for (int i = 0; i < Math.min(name.length(), bufferSize); i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Your name is: " + new String(buffer));
    }
}

